import { beerRepository } from "./beer-repository.js";
import { databaseUnavailableMessage, initializeDatabase } from "./database.js";
import { COUNTRIES, countrySearchText, findCountry, flagForCountry } from "./countries.js";
import { normalizeRoute, parseBeerDetailRoute, parseBeerEditRoute, readRouteWithQuery } from "./route-utils.mjs";
import { tastingRepository } from "./tasting-repository.js";
import { overlayManager } from "./overlay-manager.mjs";
import { renderFiveOptionRating, renderFiveOptionSummary } from "./five-option-rating.mjs";
import { normalizeTagName, splitTagInput, tagRepository } from "./tag-repository.js";
import { photoRepository } from "./photo-repository.js";
import { statsRepository } from "./stats-repository.js";
import { backupService } from "./backup-service.js";
import { App } from "@capacitor/app";

const app = document.querySelector("#route-content");
const overlayRoot = document.querySelector("#overlay-root");
const appLogo = document.querySelector("#app-logo");
const bottomNavigation = document.querySelector("[data-app-bottom-nav]");
const HOME = "/beers";
const CATEGORIES = ["拉格", "艾尔"];
const STYLES = { 拉格: ["皮尔森", "淡色拉格", "黑拉格"], 艾尔: ["IPA", "小麦啤酒", "世涛"] };
let dbError = null;
let renderSerial = 0;
let exitArmedUntil = 0;
let filters = { query: "", category: "", style: "", country_code: "", country_name: "", min_rating: "", max_rating: "", mouthfeel_rating: "", tag_ids: [], tag_match: "and", has_photo: "", order: "recent" };
let tastingFilters = { query: "", period: "all" };
const pendingFiles = new WeakMap();
const esc = (value) => String(value ?? "").replace(/[&<>"']/g, (char) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[char]));
const route = () => readRouteWithQuery(window.location, HOME);
const money = (value) => value === "" || value === null || value === undefined ? "未记录" : `¥${Number(value).toFixed(2)}`;
const displayDate = (value) => value ? new Date(value).toLocaleString("zh-CN", { dateStyle: "medium", timeStyle: "short" }) : "未记录";
const localDateTime = (value = new Date()) => { const d = value instanceof Date ? value : new Date(value); const p = (n) => String(n).padStart(2, "0"); return `${d.getFullYear()}-${p(d.getMonth() + 1)}-${p(d.getDate())}T${p(d.getHours())}:${p(d.getMinutes())}`; };
const stars = (value, max = 5) => value === "" || value === null || value === undefined ? "未评分" : `${"★".repeat(Math.min(max, Number(value)))}${"☆".repeat(Math.max(0, max - Number(value)))}`;

function navigate(path, replace = false) { const target = `#${path}`; if (replace) window.history.replaceState({}, "", target); else window.history.pushState({}, "", target); render(); }
function shell(content, title, subtitle = "") { return `<div class="local-shell"><div class="local-page-heading"><h1 class="local-page-title">${esc(title)}</h1>${subtitle ? `<p class="local-subtitle">${esc(subtitle)}</p>` : ""}</div>${content}</div>`; }
function button(label, path, className = "") { return `<a class="local-button ${className}" href="#${path}" data-route="${path}">${esc(label)}</a>`; }
function emptyState(icon, title, text, action = "") { return `<section class="local-card local-empty"><div class="local-empty-icon" aria-hidden="true">${icon}</div><h2>${esc(title)}</h2><p>${esc(text)}</p>${action}</section>`; }
function pageBack(path = HOME) { return `<button type="button" class="local-back-button" data-back-path="${path}">← 返回</button>`; }

const shellDebug = { logoNode: appLogo, headerNode: document.querySelector("[data-app-header]"), bottomNavigationNode: bottomNavigation, routeContentNode: app, navigationCount: 0 };
globalThis.__BEER_JOURNAL_SHELL_DEBUG__ = shellDebug;
function verifyShellStability() { return shellDebug.logoNode === document.querySelector("#app-logo") && shellDebug.headerNode === document.querySelector("[data-app-header]") && shellDebug.bottomNavigationNode === document.querySelector("[data-app-bottom-nav]") && shellDebug.routeContentNode === document.querySelector("#route-content"); }
async function preloadLogo() { if (!appLogo) return; appLogo.loading = "eager"; appLogo.decoding = "async"; if (appLogo.decode) await appLogo.decode().catch(() => {}); }

function tagPills(tags = []) { return tags.length ? `<div class="local-tag-list">${tags.slice(0, 5).map((tag) => `<span class="local-tag-pill">🍺 ${esc(tag.name || tag)}</span>`).join("")}</div>` : `<span class="local-muted">暂无风味标签</span>`; }
function tagEditor(tags = []) {
  const names = tags.map((tag) => typeof tag === "string" ? tag : tag.name).filter(Boolean);
  return `<section class="local-tag-editor" data-tag-editor data-tags="${esc(JSON.stringify(names))}"><label>风味标签</label><div class="local-tag-chips" data-tag-chips>${names.map((name) => `<span class="local-tag-pill">${esc(name)} <button type="button" data-remove-tag="${esc(name)}" aria-label="删除标签">×</button><input type="hidden" name="flavor_tags" value="${esc(name)}"></span>`).join("")}</div><div class="local-tag-entry"><input type="search" data-tag-input placeholder="输入后回车添加" autocomplete="off"><button type="button" class="local-button secondary" data-add-tag>添加</button></div><div class="local-tag-suggestions" data-tag-suggestions hidden></div></section>`;
}
function photoGallery(photos = [], editable = false, ownerType = "", ownerId = "") {
  return `<section class="photo-section" data-photo-section data-owner-type="${esc(ownerType)}" data-owner-id="${esc(ownerId)}"><div class="local-section-title"><h2>照片</h2>${editable ? `<span>支持多张照片</span>` : ""}</div><div class="photo-grid" data-photo-grid>${photos.map((photo) => `<figure class="photo-item" data-photo-id="${esc(photo.id)}"><img data-photo-path="${esc(photo.local_path || "")}" alt="啤酒照片" draggable="false"><div class="photo-item-actions">${editable ? `<button type="button" class="photo-delete" data-photo-delete="${esc(photo.id)}">删除</button><button type="button" class="photo-cover" data-photo-cover="${esc(photo.id)}">${photo.is_cover ? "封面" : "设为封面"}</button>` : ""}</div></figure>`).join("")}</div>${editable ? `<div class="photo-actions"><label class="photo-upload-card"><span>＋</span><strong>添加照片</strong><small>从相册选择</small><input type="file" accept="image/*" multiple data-photo-input hidden></label><button class="local-button secondary" type="button" data-camera-photo>拍照</button></div>` : ""}</section>`;
}
function hydratePhotoImages(root = document) { root.querySelectorAll("img[data-photo-path]").forEach(async (img) => { try { img.src = await photoRepository.readDataUrl(img.dataset.photoPath); img.classList.add("is-loaded"); } catch { img.classList.add("is-missing"); } }); }
async function savePendingPhotos(form, ownerType, ownerId) { const files = pendingFiles.get(form) || []; for (const file of files) await photoRepository.addPhoto({ ownerType, ownerId, source: file }); pendingFiles.delete(form); }

function beerCard(beer) {
  const country = findCountry(beer.country_code, beer.country_name);
  const stats = beer.tasting_count === undefined ? "" : `品饮 ${beer.tasting_count} 次`;
  return `<a class="local-beer-card" href="#/beers/${beer.id}" data-route="/beers/${beer.id}"><div class="beer-card-media">${beer.cover_photo ? `<img data-photo-path="${esc(beer.cover_photo.local_path)}" alt="${esc(beer.name)}" draggable="false">` : `<div class="beer-placeholder">🍺</div>`}</div><div class="beer-card-body"><div class="beer-card-country">${country.flag} ${esc(country.name)}</div><h2>${esc(beer.name)}</h2><p>${esc(beer.brand || "未填写品牌")}</p><div class="local-beer-meta"><span>${esc(beer.category || "未分类")}</span><span>${esc(beer.style || "未填写风格")}</span></div><div class="beer-card-rating"><strong>${beer.average_rating || beer.overall_rating || "—"}</strong><span>${stars(beer.average_rating || beer.overall_rating, 10)}</span></div>${tagPills(beer.flavor_tags)}<div class="local-beer-footer"><span>${stats}</span>${beer.is_new_collection ? `<span class="status-pill">新收藏</span>` : ""}</div></div></a>`;
}

function ratingSummary(beer) { return `<section class="local-card experience-card"><h2>我的风格评价</h2>${renderFiveOptionSummary("mouthfeel_rating", beer.mouthfeel_rating)}${renderFiveOptionSummary("bitterness_rating", beer.bitterness_rating)}${renderFiveOptionSummary("complexity_rating", beer.complexity_rating)}</section>`; }
function renderFilterSheet(tags = []) {
  const country = findCountry(filters.country_code, filters.country_name);
  const styles = filters.category ? STYLES[filters.category] || [] : Object.values(STYLES).flat();
  return `<div class="local-sheet-overlay" data-filter-overlay></div><section class="local-sheet filter-sheet" data-filter-sheet><header class="local-sheet-head"><h2>筛选与排序</h2><button class="local-sheet-close" type="button" data-filter-close aria-label="关闭">×</button></header><div class="filter-sheet__body"><section class="filter-section"><h3>大分类</h3><div class="local-choice-grid"><button type="button" class="local-choice${!filters.category ? " is-selected" : ""}" data-filter-category="">全部</button>${CATEGORIES.map((item) => `<button type="button" class="local-choice${filters.category === item ? " is-selected" : ""}" data-filter-category="${esc(item)}">${esc(item)}</button>`).join("")}</div></section><section class="filter-section"><h3>风格</h3><div class="local-choice-grid">${styles.map((item) => `<button type="button" class="local-choice${filters.style === item ? " is-selected" : ""}" data-filter-style="${esc(item)}">${esc(item)}</button>`).join("")}</div></section><section class="filter-section"><h3>国家</h3><button class="local-picker-trigger" type="button" data-filter-country><span>国家</span><strong>${country.flag} ${esc(country.name)}</strong></button></section><section class="filter-section"><h3>风味标签</h3><div class="local-choice-grid">${tags.map((tag) => `<button type="button" class="local-choice${filters.tag_ids.includes(tag.id) ? " is-selected" : ""}" data-filter-tag="${esc(tag.id)}">${esc(tag.name)}${tag.usage_count ? ` · ${tag.usage_count}` : ""}</button>`).join("") || `<p class="local-muted">暂无可筛选标签</p>`}</div></section><section class="filter-section"><h3>标签匹配</h3><div class="local-choice-grid"><button type="button" class="local-choice${filters.tag_match === "and" ? " is-selected" : ""}" data-filter-match="and">全部标签</button><button type="button" class="local-choice${filters.tag_match === "or" ? " is-selected" : ""}" data-filter-match="or">任一标签</button></div></section><section class="filter-section"><h3>照片</h3><div class="local-choice-grid"><button type="button" class="local-choice${filters.has_photo === "" ? " is-selected" : ""}" data-filter-photo="">全部</button><button type="button" class="local-choice${filters.has_photo === "true" ? " is-selected" : ""}" data-filter-photo="true">有照片</button><button type="button" class="local-choice${filters.has_photo === "false" ? " is-selected" : ""}" data-filter-photo="false">无照片</button></div></section><section class="filter-section filter-section--rating"><h3>评分范围</h3><div class="local-range"><label>最低评分<input type="number" step="0.5" min="0" max="10" data-filter-min value="${esc(filters.min_rating)}"></label><label>最高评分<input type="number" step="0.5" min="0" max="10" data-filter-max value="${esc(filters.max_rating)}"></label></div></section><section class="filter-section"><h3>排序</h3><div class="local-choice-grid"><button type="button" class="local-choice${filters.order === "recent" ? " is-selected" : ""}" data-filter-order="recent">最近品饮</button><button type="button" class="local-choice${filters.order === "rating" ? " is-selected" : ""}" data-filter-order="rating">平均评分</button><button type="button" class="local-choice${filters.order === "tastings" ? " is-selected" : ""}" data-filter-order="tastings">品饮次数</button></div></section></div><footer class="filter-sheet__footer"><button class="local-button" type="button" data-filter-apply>应用筛选</button><button class="local-button secondary" type="button" data-filter-reset>重置</button></footer></section>`;
}
function activeFilterSummary() { const items = []; if (filters.category) items.push(["category", filters.category]); if (filters.style) items.push(["style", filters.style]); if (filters.country_name) items.push(["country", `${findCountry(filters.country_code, filters.country_name).flag} ${filters.country_name}`]); if (filters.tag_ids.length) items.push(["tag", `${filters.tag_ids.length} 个标签`]); if (filters.has_photo) items.push(["photo", filters.has_photo === "true" ? "有照片" : "无照片"]); if (filters.min_rating || filters.max_rating) items.push(["rating", `${filters.min_rating || 0}–${filters.max_rating || 10} 分`]); return items.length ? `<div class="local-filter-summary">${items.map(([key, value]) => `<button type="button" class="filter-chip" data-clear-filter="${key}">${esc(value)} ×</button>`).join("")}</div>` : ""; }

async function renderBeerListPage() {
  const beers = await beerRepository.listBeers({ ...filters, tag_ids: filters.tag_ids });
  const stats = await statsRepository.getDashboard().catch(() => ({ core: { beer_count: beers.length } }));
  const tags = await tagRepository.listAvailableFilterTags();
  globalThis.__beerJournalAvailableTags = tags;
  await Promise.all(beers.map(async (beer) => { const photos = await photoRepository.listForOwner("beer", beer.id).catch(() => []); beer.cover_photo = photos.find((photo) => photo.is_cover) || photos[0]; beer.tasting_count = beer.tasting_count ?? undefined; beer.is_new_collection = beer.created_at && Date.now() - new Date(beer.created_at).getTime() < 30 * 86400000; }));
  const cards = beers.length ? beers.map(beerCard).join("") : emptyState("🍺", "还没有啤酒收藏", "添加第一款啤酒，开始建立你的本地收藏。", `<button class="local-button" type="button" data-add-beer>添加啤酒</button>`);
  return shell(`<section class="collection-overview local-card"><span>我的啤酒</span><strong>${stats.core?.beer_count ?? beers.length} 款收藏</strong><small>${stats.core?.tasting_count ?? 0} 次品饮</small></section><form class="local-search" data-search-form><span aria-hidden="true">⌕</span><input name="query" type="search" placeholder="搜索啤酒、品牌、国家、标签" value="${esc(filters.query)}"><button type="submit">搜索</button></form>${activeFilterSummary()}<button type="button" class="filter-entry-card" data-filter-open><span>筛选与排序</span><span aria-hidden="true">›</span></button><div class="beer-card-list">${cards}</div><button class="fab" type="button" data-add-beer aria-label="添加啤酒">＋</button>`, "我的啤酒", "你的私人收藏");
}

function countryTrigger(code, name) { const country = findCountry(code, name); return `<button type="button" class="local-picker-trigger" data-country-picker><span>国家</span><strong>${country.flag} ${esc(country.name)}</strong></button><input type="hidden" name="country_code" value="${esc(code || "")}"><input type="hidden" name="country_name" value="${esc(name || "")}">`; }
function choiceTrigger(type, value, placeholder) { return `<button type="button" class="local-picker-trigger" data-choice-picker="${type}"><span>${type === "category" ? "大分类" : "风格"}</span><strong>${esc(value || placeholder)}</strong></button><input type="hidden" name="${type}" value="${esc(value || "")}">`; }
function beerForm(beer = null) {
  const formId = beer ? `data-beer-id="${esc(beer.id)}"` : "";
  return `<form class="local-form" data-beer-form ${formId}><div class="form-topbar">${pageBack(beer ? `/beers/${beer.id}` : HOME)}<h1>${beer ? "编辑啤酒" : "添加啤酒"}</h1></div>${photoGallery(beer?.photos || [], true, "beer", beer?.id || "")}<label>啤酒名称<input required name="name" value="${esc(beer?.name)}" placeholder="例如：Sierra Nevada Pale Ale"></label><label>品牌<input name="brand" value="${esc(beer?.brand)}"></label><label>酒厂<input name="brewery" value="${esc(beer?.brewery)}"></label>${countryTrigger(beer?.country_code, beer?.country_name)}${choiceTrigger("category", beer?.category, "请选择大分类")}${choiceTrigger("style", beer?.style, "请选择风格")}<div class="form-grid"><label>ABV (%)<input type="number" step="0.01" min="0" max="100" name="abv" value="${esc(beer?.abv)}"></label><label>Plato<input type="number" step="0.01" min="0" name="plato" value="${esc(beer?.plato)}"></label><label>默认容量 (ml)<input type="number" min="1" name="default_volume_ml" value="${esc(beer?.default_volume_ml)}"></label><label>总体评分<input type="number" step="0.5" min="0" max="10" name="overall_rating" value="${esc(beer?.overall_rating)}"></label></div>${renderFiveOptionRating("mouthfeel_rating", beer?.mouthfeel_rating)}${renderFiveOptionRating("bitterness_rating", beer?.bitterness_rating)}${renderFiveOptionRating("complexity_rating", beer?.complexity_rating)}${tagEditor(beer?.flavor_tags || [])}<label>个人感想<textarea name="personal_note" rows="4">${esc(beer?.personal_note)}</textarea></label><button class="local-button primary" type="submit">保存啤酒</button></form>`;
}

function tastingCard(tasting) { return `<a class="tasting-card local-card" href="#/tastings/${tasting.id}" data-route="/tastings/${tasting.id}"><div class="tasting-card-date">${esc(displayDate(tasting.consumed_at))}</div><h2>${esc(tasting.beer_name)}</h2><p>${esc(tasting.note || "暂无笔记")}</p><div class="tasting-meta"><span>${esc(tasting.volume_ml || "—")} ml × ${esc(tasting.bottle_count || "—")}</span><strong>${tasting.rating || "—"}</strong><button type="button" data-tasting-actions="${esc(tasting.id)}" aria-label="更多操作">•••</button></div></a>`; }
function tastingListPage(tastings, stats) { const periods = [["all", "全部"], ["recent", "最近30天"], ["year", "本年度"], ["history", "历史"]]; return shell(`<section class="journal-stats"><div><strong>${stats.tasting_count || 0}</strong><span>总品饮</span></div><div><strong>${stats.year_count || 0}</strong><span>本年度</span></div><div><strong>${stats.average_rating_scaled ? (Number(stats.average_rating_scaled) / 10).toFixed(1) : "—"}</strong><span>平均评分</span></div></section><div class="period-tabs">${periods.map(([value, label]) => `<button type="button" class="${tastingFilters.period === value ? "is-selected" : ""}" data-period="${value}">${label}</button>`).join("")}</div><form class="local-search" data-tasting-search-form><span>⌕</span><input name="query" type="search" placeholder="搜索饮用记录" value="${esc(tastingFilters.query)}"><button type="submit">搜索</button></form><div class="tasting-timeline">${tastings.length ? tastings.map(tastingCard).join("") : emptyState("📝", "还没有饮用记录", "记录一次品饮，留下当时的味道。", button("记录饮用", "/tastings/new"))}</div><a class="fab" href="#/tastings/new" data-route="/tastings/new" aria-label="记录饮用">＋</a>`, "饮用记录", "你的私人饮酒日记"); }
function tastingForm(tasting = null, beer = null) { const selectedBeer = beer || tasting; return `<form class="local-form" data-tasting-form ${tasting ? `data-tasting-id="${esc(tasting.id)}"` : ""}><div class="form-topbar">${pageBack(tasting ? `/tastings/${tasting.id}` : "/tastings")}<h1>${tasting ? "编辑品饮" : "记录饮用"}</h1></div>${selectedBeer ? `<div class="local-card selected-beer"><strong>${esc(selectedBeer.name || selectedBeer.beer_name)}</strong><span>${esc(selectedBeer.brand || selectedBeer.beer_brand || "")}</span><input type="hidden" name="beer_id" value="${esc(selectedBeer.id || selectedBeer.beer_id)}"></div>` : `<label>选择啤酒<select name="beer_id" data-beer-select><option value="">请选择啤酒</option></select></label>`}${photoGallery(tasting?.photos || [], true, "tasting", tasting?.id || "")}<label>饮用时间<input type="text" readonly name="consumed_at" data-date-picker value="${esc(localDateTime(tasting?.consumed_at || new Date()))}"></label><label>地点<input name="location" value="${esc(tasting?.location)}"></label><div class="form-grid"><label>容量 (ml)<input type="number" min="1" name="volume_ml" value="${esc(tasting?.volume_ml || selectedBeer?.default_volume_ml)}"></label><label>瓶数<input type="number" min="1" step="1" name="bottle_count" value="${esc(tasting?.bottle_count || 1)}"></label><label>价格 (¥)<input type="number" min="0" step="0.01" name="price" value="${esc(tasting?.price)}"></label><label>本次评分<input type="number" min="0" max="10" step="0.5" name="rating" value="${esc(tasting?.rating)}"></label></div><label>购买渠道<select name="purchase_channel"><option value="">未选择</option><option value="online" ${tasting?.purchase_channel === "online" ? "selected" : ""}>线上</option><option value="offline" ${tasting?.purchase_channel === "offline" ? "selected" : ""}>线下</option><option value="gift" ${tasting?.purchase_channel === "gift" ? "selected" : ""}>赠送</option></select></label><label>品饮笔记<textarea name="note" rows="5">${esc(tasting?.note)}</textarea></label><button class="local-button primary" type="submit">保存品饮</button></form>`; }
function profilePage(data) { const c = data.core || {}; const pref = data.preferences || {}; const bars = (items = []) => items.length ? `<div class="bar-chart">${items.slice(0, 8).map((item) => `<div><span>${esc(item.value)}</span><i style="--bar:${Math.max(8, Math.min(100, item.count * 16))}%"></i><b>${item.count}</b></div>`).join("")}</div>` : `<p class="local-muted">暂无数据</p>`; return shell(`<section class="profile-hero local-card"><span>我的啤酒画像</span><div class="profile-numbers"><div><strong>${c.beer_count || 0}</strong><small>收藏</small></div><div><strong>${c.tasting_count || 0}</strong><small>品饮</small></div><div><strong>${c.average_tasting_rating_scaled ? (Number(c.average_tasting_rating_scaled) / 10).toFixed(1) : "—"}</strong><small>平均</small></div></div></section><section class="local-card"><h2>收藏概览</h2><div class="stat-grid"><span>总瓶数 <b>${c.bottle_count || 0}</b></span><span>总容量 <b>${c.total_volume_ml || 0} ml</b></span><span>探索国家 <b>${c.country_count || 0}</b></span><span>品牌 <b>${c.brand_count || 0}</b></span><span>酒厂 <b>${c.brewery_count || 0}</b></span><span>风格 <b>${c.style_count || 0}</b></span><span>总花费 <b>${money((c.total_spend_scaled || 0) / 100)}</b></span><span>平均每次 <b>${money((c.average_tasting_price_scaled || 0) / 100)}</b></span></div></section><section class="local-card"><h2>类型分布</h2>${bars(pref.category)}</section><section class="local-card"><h2>风格分布</h2>${bars(pref.style)}</section><section class="local-card"><h2>国家分布</h2>${bars(pref.country)}</section><section class="local-card"><h2>风味标签</h2>${bars(data.flavor_tags)}</section><section class="local-card"><h2>近12个月趋势</h2>${bars((data.monthly || []).map((item) => ({ value: item.month, count: item.tasting_count })))}</section><section class="local-card data-management"><h2>数据管理</h2>${button("回收站", "/trash", "secondary")}<button class="local-button secondary" type="button" data-backup-export>导出备份</button><label class="local-button secondary">导入备份<input type="file" accept="application/json" data-backup-import hidden></label><button class="local-button danger" type="button" data-clear-data>清空本地数据</button></section>`, "个人数据", "只保存在你的设备上"); }
function beerDetailPage(beer, tastings, stats, photos) { const country = findCountry(beer.country_code, beer.country_name); return shell(`<div class="detail-actions">${pageBack(HOME)}${button("编辑资料", `/beers/${beer.id}/edit`, "secondary")}<button class="local-button danger" type="button" data-delete-beer="${esc(beer.id)}">删除</button></div><section class="detail-hero local-card">${photos[0] ? `<img data-photo-path="${esc(photos[0].local_path)}" alt="${esc(beer.name)}" draggable="false">` : `<div class="detail-placeholder">🍺</div>`}<div class="beer-card-country">${country.flag} ${esc(country.name)}</div><h1>${esc(beer.name)}</h1><p>${esc(beer.brand || "")}</p><span>${esc(beer.category)} · ${esc(beer.style)}</span></section><section class="local-card stat-grid"><span>品饮次数 <b>${stats.tasting_count || 0}</b></span><span>总瓶数 <b>${stats.bottle_count || 0}</b></span><span>平均评分 <b>${stats.average_rating_scaled ? (Number(stats.average_rating_scaled) / 10).toFixed(1) : "—"}</b></span><span>最近品饮 <b>${stats.latest_consumed_at ? displayDate(stats.latest_consumed_at) : "—"}</b></span></section><section class="local-card basic-info"><h2>基础资料</h2><p>ABV ${beer.abv || "—"}% · Plato ${beer.plato || "—"} · 默认容量 ${beer.default_volume_ml || "—"} ml</p><p>${esc(beer.personal_note || "暂无个人感想")}</p></section>${ratingSummary(beer)}<section class="local-card"><h2>风味标签</h2>${tagPills(beer.flavor_tags)}</section>${photos.length ? photoGallery(photos, false) : ""}<section class="local-card"><div class="local-section-title"><h2>我的品饮历史</h2>${button("再次品饮", `/tastings/new?beer_id=${beer.id}`, "primary")}</div><div class="tasting-timeline">${tastings.length ? tastings.map(tastingCard).join("") : `<p class="local-muted">还没有品饮记录</p>`}</div></section>`, beer.name, `${country.name} · ${beer.style || "未分类"}`); }
function tastingDetailPage(tasting, photos) { return shell(`<div class="detail-actions">${pageBack(`/beers/${tasting.beer_id}`)}${button("编辑记录", `/tastings/${tasting.id}/edit`, "secondary")}<button class="local-button danger" type="button" data-delete-tasting="${esc(tasting.id)}">删除</button></div><section class="local-card detail-hero"><h1>${esc(tasting.beer_name)}</h1><p>${esc(tasting.beer_brand || "")}</p><strong>${esc(displayDate(tasting.consumed_at))}</strong></section>${photos.length ? photoGallery(photos, false) : ""}<section class="local-card"><h2>饮用信息</h2><div class="stat-grid"><span>地点 <b>${esc(tasting.location || "—")}</b></span><span>容量 <b>${tasting.volume_ml || "—"} ml</b></span><span>瓶数 <b>${tasting.bottle_count || "—"}</b></span><span>价格 <b>${money(tasting.price)}</b></span><span>评分 <b>${tasting.rating || "—"}</b></span></div><p class="tasting-note">${esc(tasting.note || "暂无笔记")}</p></section>`, "饮用日记", displayDate(tasting.consumed_at)); }
function secondaryPage(title, text, action = "") { return shell(`${pageBack(HOME)}${emptyState("ℹ️", title, text, action)}`, title); }

async function openCountryPicker(target = "form") {
  const restoreFocus = document.activeElement; const root = document.createElement("div"); root.className = "local-country-picker"; root.innerHTML = `<div class="local-sheet-overlay" data-country-close></div><section class="local-sheet local-country-sheet"><div class="local-sheet-head"><h2>选择国家</h2><button type="button" class="local-sheet-close" data-country-close>×</button></div><input class="local-country-search" type="search" placeholder="搜索中文、英文、代码或别名" data-country-search><div class="local-country-list" data-country-list></div></section>`; document.body.append(root); overlayManager.openOverlay({ id: "country-picker", element: root, restoreFocus });
  const records = [...COUNTRIES]; const beers = await beerRepository.listBeers().catch(() => []); const seen = new Set(records.map((item) => item[1].toLowerCase())); beers.forEach((beer) => { const name = String(beer.country_name || "").trim(); if (name && !beer.country_code && !seen.has(name.toLowerCase())) { seen.add(name.toLowerCase()); records.push(["", name, name, [name]]); } });
  const list = root.querySelector("[data-country-list]"); const draw = (query = "") => { const q = String(query).trim(); const matches = records.filter((item) => !q || countrySearchText(item).includes(q.toLowerCase())); const custom = q && !matches.length ? `<button class="local-country-custom" type="button" data-custom-country="${esc(q)}">🌐 使用“${esc(q)}”</button>` : ""; list.innerHTML = custom + matches.map(([code, name, english, aliases]) => `<button class="local-country-option" type="button" data-country-code="${esc(code)}" data-country-name="${esc(name)}"><span>${flagForCountry(code)}</span><strong>${esc(name)}</strong><small>${esc(english)}${aliases?.length ? ` · ${esc(aliases[0])}` : ""}</small></button>`).join(""); }; draw(); root.querySelector("[data-country-search]").addEventListener("input", (event) => draw(event.target.value));
  root.addEventListener("click", (event) => { if (event.target.closest("[data-country-close]")) { overlayManager.closeOverlay("country-picker"); return; } const option = event.target.closest("[data-country-code]"); const custom = event.target.closest("[data-custom-country]"); if (!option && !custom) return; const code = custom ? "" : option.dataset.countryCode; const name = custom ? custom.dataset.customCountry : option.dataset.countryName; if (target === "filter") { filters.country_code = code; filters.country_name = name; overlayManager.closeOverlay("country-picker"); renderFilterPortal(); return; } const form = document.querySelector("[data-beer-form]"); if (form) { form.querySelector('[name="country_code"]').value = code; form.querySelector('[name="country_name"]').value = name; form.querySelector("[data-country-picker] strong").textContent = `${flagForCountry(code)} ${name}`; } overlayManager.closeOverlay("country-picker"); }); root.querySelector("[data-country-search]").focus();
}
function openChoicePicker(type) { const form = document.querySelector("[data-beer-form]"); if (!form) return; const current = form.querySelector(`[name="${type}"]`).value; const options = type === "category" ? CATEGORIES : (STYLES[form.querySelector('[name="category"]').value] || Object.values(STYLES).flat()); const root = document.createElement("div"); const id = `choice-${type}`; root.className = "local-choice-picker"; root.innerHTML = `<div class="local-sheet-overlay" data-choice-close></div><section class="local-sheet"><div class="local-sheet-head"><h2>选择${type === "category" ? "啤酒大类" : "啤酒风格"}</h2><button type="button" class="local-sheet-close" data-choice-close>×</button></div><div class="local-choice-grid">${options.map((item) => `<button type="button" class="local-choice${item === current ? " is-selected" : ""}" data-choice-value="${esc(item)}">${esc(item)}</button>`).join("")}</div></section>`; document.body.append(root); overlayManager.openOverlay({ id, element: root, restoreFocus: document.activeElement }); root.addEventListener("click", (event) => { if (event.target.closest("[data-choice-close]")) { overlayManager.closeOverlay(id); return; } const option = event.target.closest("[data-choice-value]"); if (!option) return; form.querySelector(`[name="${type}"]`).value = option.dataset.choiceValue; form.querySelector(`[data-choice-picker="${type}"] strong`).textContent = option.dataset.choiceValue; if (type === "category") { form.querySelector('[name="style"]').value = ""; form.querySelector('[data-choice-picker="style"] strong').textContent = "请选择风格"; } overlayManager.closeOverlay(id); }); }
function openDatePicker(input) { const current = new Date(input.value || new Date()); const root = document.createElement("div"); const id = "datetime-picker"; const values = { year: current.getFullYear(), month: current.getMonth() + 1, day: current.getDate(), hour: current.getHours(), minute: current.getMinutes() }; root.className = "local-date-picker"; root.innerHTML = `<div class="local-sheet-overlay" data-date-close></div><section class="local-sheet"><div class="local-sheet-head"><h2>选择品饮时间</h2><button type="button" class="local-sheet-close" data-date-close>×</button></div><div class="date-wheel-grid">${[["year", "年", 2000, 2035], ["month", "月", 1, 12], ["day", "日", 1, 31], ["hour", "ʱ", 0, 23], ["minute", "分", 0, 59]].map(([key, label, min, max]) => `<label>${label}<select data-date-part="${key}">${Array.from({ length: max - min + 1 }, (_, i) => min + i).map((v) => `<option value="${v}" ${v === values[key] ? "selected" : ""}>${String(v).padStart(2, "0")}</option>`).join("")}</select></label>`).join("")}</div><footer class="local-actions"><button type="button" class="local-button secondary" data-date-close>取消</button><button type="button" class="local-button" data-date-confirm>确认</button></footer></section>`; document.body.append(root); overlayManager.openOverlay({ id, element: root, restoreFocus: input }); root.addEventListener("click", (event) => { if (event.target.closest("[data-date-close]")) { overlayManager.closeOverlay(id); return; } if (event.target.closest("[data-date-confirm]")) { const d = new Date(Number(root.querySelector('[data-date-part="year"]').value), Number(root.querySelector('[data-date-part="month"]').value) - 1, Number(root.querySelector('[data-date-part="day"]').value), Number(root.querySelector('[data-date-part="hour"]').value), Number(root.querySelector('[data-date-part="minute"]').value)); input.value = localDateTime(d); overlayManager.closeOverlay(id); } }); }
function openDeleteConfirm(kind, id, restoreFocus = null) { const overlayId = `delete-${kind}`; const root = document.createElement("div"); root.className = "local-delete-confirm"; root.innerHTML = `<div class="local-sheet-overlay" data-confirm-close></div><section class="local-sheet"><div class="local-sheet-head"><h2>确认删除</h2><button type="button" class="local-sheet-close" data-confirm-close>×</button></div><p>这条记录会被软删除，可在回收站恢复。</p><div class="local-actions"><button class="local-button secondary" type="button" data-confirm-close>取消</button><button class="local-button danger" type="button" data-confirm-accept data-delete-kind="${kind}" data-delete-id="${esc(id)}">确认删除</button></div></section>`; document.body.append(root); overlayManager.openOverlay({ id: overlayId, element: root, restoreFocus }); }
function firstTastingSheet(beer) { const root = document.createElement("div"); root.className = "local-first-tasting"; root.innerHTML = `<div class="local-sheet-overlay" data-first-close></div><section class="local-sheet"><div class="local-sheet-head"><h2>添加首次品饮？</h2></div><p>现在记录这次饮用，或稍后再补充。</p><div class="local-actions"><button class="local-button secondary" data-first-later>稍后添加</button><button class="local-button" data-first-add>添加首次品饮</button></div></section>`; document.body.append(root); overlayManager.openOverlay({ id: "first-tasting", element: root }); root.addEventListener("click", (event) => { if (event.target.closest("[data-first-later]")) { overlayManager.closeOverlay("first-tasting"); navigate(`/beers/${beer.id}`); } if (event.target.closest("[data-first-add]")) { overlayManager.closeOverlay("first-tasting"); navigate(`/tastings/new?beer_id=${beer.id}`); } }); }
function renderFilterPortal() { const portal = document.querySelector("#overlay-root"); if (!portal) return; portal.innerHTML = renderFilterSheet(window.__beerJournalAvailableTags || []); const sheet = portal.querySelector("[data-filter-sheet]"); const backdrop = portal.querySelector("[data-filter-overlay]"); portal.classList.add("filter-overlay-root", "is-open"); overlayManager.openOverlay({ id: "filter-sheet", element: sheet, removeElement: false, restoreFocus: document.querySelector("[data-filter-open]"), onClose: () => { portal.classList.remove("is-open"); portal.innerHTML = ""; } }); }

function updateTagEditor(editor, names) { editor.dataset.tags = JSON.stringify(names); editor.querySelector("[data-tag-chips]").innerHTML = names.map((name) => `<span class="local-tag-pill">${esc(name)} <button type="button" data-remove-tag="${esc(name)}">×</button><input type="hidden" name="flavor_tags" value="${esc(name)}"></span>`).join(""); editor.querySelector("[data-tag-input]").value = ""; }
function addTags(editor, value) { const names = splitTagInput([...(JSON.parse(editor.dataset.tags || "[]")), ...splitTagInput(value)]); updateTagEditor(editor, names); }

async function render() {
  const serial = ++renderSerial; const current = normalizeRoute(route().split("?")[0]); if (!app) return; try {
    if (current === HOME || current === "/") app.innerHTML = await renderBeerListPage();
    else if (current === "/profile") app.innerHTML = profilePage(await statsRepository.getDashboard());
    else if (current === "/tastings") { const all = await tastingRepository.listTastings({ query: tastingFilters.query, ...(tastingFilters.period === "recent" ? { from: new Date(Date.now() - 30 * 86400000).toISOString() } : tastingFilters.period === "year" ? { from: `${new Date().getFullYear()}-01-01` } : tastingFilters.period === "history" ? { to: `${new Date().getFullYear()}-01-01` } : {}) }); const stats = await tastingRepository.getStats(); stats.year_count = (await tastingRepository.listTastings({ from: `${new Date().getFullYear()}-01-01` })).length; app.innerHTML = tastingListPage(all, stats); }
    else if (current === "/tastings/new") { const query = new URLSearchParams(route().split("?")[1] || ""); const beer = query.get("beer_id") ? await beerRepository.getBeerById(query.get("beer_id")) : null; app.innerHTML = beer ? tastingForm(null, beer) : shell(tastingBeerSelectPage(await beerRepository.listBeers()), "选择啤酒", "选择已有啤酒开始记录"); }
    else if (current === "/trash") { const beers = await beerRepository.listDeletedBeers(); const tastings = await tastingRepository.listDeletedTastings(); const photos = await photoRepository.listDeletedPhotos(); app.innerHTML = shell(`${pageBack("/profile")}<section class="local-card"><h2>已删除啤酒</h2>${beers.map((beer) => `<div class="trash-row"><span>${esc(beer.name)}</span><button type="button" data-restore-beer="${beer.id}">恢复</button></div>`).join("") || `<p class="local-muted">暂无已删除啤酒</p>`}</section><section class="local-card"><h2>已删除品饮</h2>${tastings.filter((t) => t.deleted_at).map((t) => `<div class="trash-row"><span>${esc(t.beer_name)} · ${esc(displayDate(t.consumed_at))}</span><button type="button" data-restore-tasting="${t.id}">恢复</button></div>`).join("") || `<p class="local-muted">暂无已删除品饮</p>`}</section><section class="local-card"><h2>已删除照片</h2>${photos.map((photo) => `<div class="trash-row"><span>${esc(photo.id)}</span><button type="button" data-restore-photo="${photo.id}">恢复</button></div>`).join("") || `<p class="local-muted">暂无已删除照片</p>`}</section>`, "回收站"); }
    else if (current === "/settings") app.innerHTML = shell(`${pageBack("/profile")}${emptyState("⚙️", "数据管理", "备份、恢复和清空数据都在个人数据页完成。", button("返回个人数据", "/profile"))}`, "设置");
    else if (current === "/beers/new") app.innerHTML = shell(beerForm(), "添加啤酒", "记录一款新的啤酒收藏");
    else if (parseBeerEditRoute(current)) { const id = parseBeerEditRoute(current); const beer = await beerRepository.getBeerById(id); if (!beer) app.innerHTML = secondaryPage("找不到啤酒", "这条记录可能已被删除。", button("返回列表", HOME)); else { beer.photos = await photoRepository.listForOwner("beer", beer.id); app.innerHTML = shell(beerForm(beer), "编辑啤酒", "修改收藏资料"); } }
    else if (parseBeerDetailRoute(current)) { const id = parseBeerDetailRoute(current); const beer = await beerRepository.getBeerById(id); if (!beer) app.innerHTML = secondaryPage("找不到啤酒", "这条记录可能已被删除。", button("返回列表", HOME)); else { const [tastings, stats, photos] = await Promise.all([tastingRepository.listTastingsByBeerId(id), tastingRepository.getStatsByBeerId(id), photoRepository.listForOwner("beer", id)]); app.innerHTML = beerDetailPage(beer, tastings, stats, photos); } }
    else { const tastingMatch = current.match(/^\/tastings\/([0-9a-f-]{36})(\/edit)?$/i); if (tastingMatch) { const tasting = await tastingRepository.getTastingById(tastingMatch[1]); if (!tasting) app.innerHTML = secondaryPage("找不到品饮记录", "这条记录可能已被删除。", button("返回品饮记录", "/tastings")); else if (tastingMatch[2]) { tasting.photos = await photoRepository.listForOwner("tasting", tasting.id); app.innerHTML = shell(tastingForm(tasting), "编辑品饮", "修改本次记录"); } else { const photos = await photoRepository.listForOwner("tasting", tasting.id); app.innerHTML = tastingDetailPage(tasting, photos); } } else app.innerHTML = secondaryPage("页面不存在", "请返回我的啤酒。", button("返回我的啤酒", HOME)); }
    if (serial !== renderSerial) return; app.classList.remove("is-entering"); void app.offsetWidth; app.classList.add("is-entering"); verifyShellStability(); hydratePhotoImages(app); syncBottomNavigation();
  } catch (error) { dbError = error; app.innerHTML = shell(emptyState("⚠️", "本地数据库暂不可用", databaseUnavailableMessage(), `<button class="local-button" type="button" data-db-retry>重试</button>`), "Beer Journal"); }
}
function tastingBeerSelectPage(beers) { return `<div class="select-beer-page">${pageBack("/tastings")}<h1>选择啤酒</h1><form class="local-search" data-beer-select-search><span>⌕</span><input name="query" type="search" placeholder="搜索名称或品牌"><button type="submit">搜索</button></form><div class="beer-select-list">${beers.map((beer) => `<label class="beer-select-card"><input type="radio" name="select_beer" value="${beer.id}"><span><strong>${esc(beer.name)}</strong><small>${esc(beer.brand || "")} · ${esc(beer.country_name || "")} · ${esc(beer.category || "")} · ${esc(beer.style || "")}</small></span></label>`).join("")}</div><button type="button" class="local-button primary" data-start-selected-tasting>继续</button><section class="local-card"><h2>没有这款啤酒？</h2><p>先创建啤酒资料，再添加首次品饮。</p>${button("添加啤酒", "/beers/new")}</section></div>`; }
function syncBottomNavigation() { const current = normalizeRoute(route().split("?")[0]); bottomNavigation?.querySelectorAll("[data-route]").forEach((link) => link.classList.toggle("is-active", link.dataset.route === current || (current.startsWith("/beers/") && link.dataset.route === HOME) || (current.startsWith("/tastings/") && link.dataset.route === "/tastings"))); }

document.addEventListener("click", async (event) => {
  const add = event.target.closest("[data-add-beer]"); if (add) { event.preventDefault(); navigate("/beers/new"); return; }
  const link = event.target.closest("a[data-route]"); if (link) { event.preventDefault(); if (!overlayManager.hasOpenOverlay()) navigate(link.dataset.route); return; }
  const back = event.target.closest("[data-back-path]"); if (back) { navigate(back.dataset.backPath); return; }
  if (event.target.closest("[data-country-picker]")) { openCountryPicker("form"); return; }
  const choice = event.target.closest("[data-choice-picker]"); if (choice) { openChoicePicker(choice.dataset.choicePicker); return; }
  if (event.target.closest("[data-date-picker]")) { openDatePicker(event.target.closest("[data-date-picker]")); return; }
  const editor = event.target.closest("[data-tag-editor]"); const remove = event.target.closest("[data-remove-tag]"); if (remove && editor) { updateTagEditor(editor, JSON.parse(editor.dataset.tags || "[]").filter((name) => normalizeTagName(name) !== normalizeTagName(remove.dataset.removeTag))); return; }
  if (event.target.closest("[data-add-tag]") && editor) { addTags(editor, editor.querySelector("[data-tag-input]").value); return; }
  const suggestion = event.target.closest("[data-tag-suggestion]"); if (suggestion) { addTags(suggestion.closest("[data-tag-editor]"), suggestion.dataset.tagSuggestion); return; }
  if (event.target.closest("[data-photo-delete]")) { await photoRepository.softDeletePhoto(event.target.closest("[data-photo-delete]").dataset.photoDelete); await render(); return; }
  if (event.target.closest("[data-photo-cover]")) {
    const button = event.target.closest("[data-photo-cover]");
    const section = button.closest("[data-photo-section]");
    await photoRepository.setCover(button.dataset.photoCover, section?.dataset.ownerType, section?.dataset.ownerId);
    await render();
    return;
  }
  if (event.target.closest("[data-camera-photo]")) { const form = event.target.closest("form"); const photo = await photoRepository.takePhoto(); if (photo) pendingFiles.set(form, [...(pendingFiles.get(form) || []), photo]); return; }
  if (event.target.closest("[data-filter-open]")) { renderFilterPortal(); return; }
  if (event.target.closest("[data-filter-close], [data-filter-overlay]")) { overlayManager.closeOverlay("filter-sheet"); return; }
  const category = event.target.closest("[data-filter-category]"); if (category) { filters.category = category.dataset.filterCategory; if (!filters.category) filters.style = ""; document.querySelectorAll("[data-filter-category]").forEach((node) => node.classList.toggle("is-selected", node === category)); renderFilterPortal(); return; }
  const style = event.target.closest("[data-filter-style]"); if (style) { filters.style = style.dataset.filterStyle; renderFilterPortal(); return; }
  const tag = event.target.closest("[data-filter-tag]"); if (tag) { const id = tag.dataset.filterTag; filters.tag_ids = filters.tag_ids.includes(id) ? filters.tag_ids.filter((value) => value !== id) : [...filters.tag_ids, id]; renderFilterPortal(); return; }
  const match = event.target.closest("[data-filter-match]"); if (match) { filters.tag_match = match.dataset.filterMatch; renderFilterPortal(); return; }
  const photoFilter = event.target.closest("[data-filter-photo]"); if (photoFilter) { filters.has_photo = photoFilter.dataset.filterPhoto; renderFilterPortal(); return; }
  const order = event.target.closest("[data-filter-order]"); if (order) { filters.order = order.dataset.filterOrder; renderFilterPortal(); return; }
  const clear = event.target.closest("[data-clear-filter]"); if (clear) { if (clear.dataset.clearFilter === "category") filters.category = ""; if (clear.dataset.clearFilter === "style") filters.style = ""; if (clear.dataset.clearFilter === "country") { filters.country_code = ""; filters.country_name = ""; } if (clear.dataset.clearFilter === "tag") filters.tag_ids = []; if (clear.dataset.clearFilter === "photo") filters.has_photo = ""; if (clear.dataset.clearFilter === "rating") { filters.min_rating = ""; filters.max_rating = ""; } await render(); return; }
  if (event.target.closest("[data-filter-country]")) { openCountryPicker("filter"); return; }
  if (event.target.closest("[data-filter-reset]")) { filters = { query: "", category: "", style: "", country_code: "", country_name: "", min_rating: "", max_rating: "", mouthfeel_rating: "", tag_ids: [], tag_match: "and", has_photo: "", order: "recent" }; overlayManager.closeOverlay("filter-sheet"); await render(); return; }
  if (event.target.closest("[data-filter-apply]")) { filters.min_rating = document.querySelector("[data-filter-min]")?.value || ""; filters.max_rating = document.querySelector("[data-filter-max]")?.value || ""; overlayManager.closeOverlay("filter-sheet"); await render(); return; }
  if (event.target.closest("[data-delete-beer]")) { openDeleteConfirm("beer", event.target.closest("[data-delete-beer]").dataset.deleteBeer); return; }
  if (event.target.closest("[data-delete-tasting]")) { openDeleteConfirm("tasting", event.target.closest("[data-delete-tasting]").dataset.deleteTasting); return; }
  if (event.target.closest("[data-confirm-close]")) { overlayManager.closeTopOverlay(); return; }
  const confirm = event.target.closest("[data-confirm-accept]"); if (confirm) { const kind = confirm.dataset.deleteKind; const id = confirm.dataset.deleteId; overlayManager.closeTopOverlay(); if (kind === "beer") { await beerRepository.softDeleteBeer(id); navigate(HOME); } else { const tasting = await tastingRepository.getTastingById(id); await tastingRepository.softDeleteTasting(id); navigate(tasting ? `/beers/${tasting.beer_id}` : "/tastings"); } return; }
  const restoreBeer = event.target.closest("[data-restore-beer]"); if (restoreBeer) { await beerRepository.restoreBeer(restoreBeer.dataset.restoreBeer); await render(); return; }
  const restoreTasting = event.target.closest("[data-restore-tasting]"); if (restoreTasting) { await tastingRepository.restoreTasting(restoreTasting.dataset.restoreTasting); await render(); return; }
  const restorePhoto = event.target.closest("[data-restore-photo]"); if (restorePhoto) { await photoRepository.restorePhoto(restorePhoto.dataset.restorePhoto); await render(); return; }
  if (event.target.closest("[data-db-retry]")) { dbError = null; await render(); return; }
  if (event.target.closest("[data-start-selected-tasting]")) { const id = document.querySelector('[name="select_beer"]:checked')?.value; if (id) navigate(`/tastings/new?beer_id=${id}`); return; }
  const period = event.target.closest("[data-period]"); if (period) { tastingFilters.period = period.dataset.period; await render(); return; }
  if (event.target.closest("[data-backup-export]")) { await backupService.downloadBackup(); return; }
  if (event.target.closest("[data-clear-data]")) { if (window.confirm("确定清空本地所有数据吗？此操作不可撤销。")) { await backupService.clearAll(); await render(); } return; }
});

document.addEventListener("change", async (event) => {
  if (event.target.matches("[data-photo-input]")) {
    const form = event.target.closest("form");
    const files = [...event.target.files];
    pendingFiles.set(form, [...(pendingFiles.get(form) || []), ...files]);
    const grid = form?.querySelector("[data-photo-grid]");
    files.forEach((file) => {
      const figure = document.createElement("figure");
      figure.className = "photo-item photo-item--pending";
      figure.innerHTML = `<img alt="待上传照片" draggable="false"><figcaption>待上传</figcaption>`;
      figure.querySelector("img").src = URL.createObjectURL(file);
      grid?.append(figure);
    });
  }
  if (event.target.matches("[data-backup-import]")) { try { await backupService.importFile(event.target.files[0]); await render(); } catch (error) { window.alert(error.message); } }
});
document.addEventListener("input", async (event) => { if (!event.target.matches("[data-tag-input]")) return; const suggestions = event.target.closest("[data-tag-editor]")?.querySelector("[data-tag-suggestions]"); const query = event.target.value.trim(); if (!query) { suggestions.hidden = true; return; } const matches = await tagRepository.searchTags(query); suggestions.innerHTML = matches.slice(0, 8).map((tag) => `<button type="button" data-tag-suggestion="${esc(tag.name)}">${esc(tag.name)}</button>`).join(""); suggestions.hidden = !matches.length; });
document.addEventListener("keydown", (event) => { if (event.key === "Enter" && event.target.matches("[data-tag-input]")) { event.preventDefault(); addTags(event.target.closest("[data-tag-editor]"), event.target.value); } });
document.addEventListener("submit", async (event) => {
  if (event.target.matches("[data-search-form]")) { event.preventDefault(); filters.query = new FormData(event.target).get("query") || ""; await render(); return; }
  if (event.target.matches("[data-tasting-search-form]")) { event.preventDefault(); tastingFilters.query = new FormData(event.target).get("query") || ""; await render(); return; }
  if (event.target.matches("[data-beer-select-search]")) { event.preventDefault(); const query = new FormData(event.target).get("query"); const beers = await beerRepository.searchBeers(query); event.target.closest(".select-beer-page").querySelector(".beer-select-list").innerHTML = beers.map((beer) => `<label class="beer-select-card"><input type="radio" name="select_beer" value="${beer.id}"><span><strong>${esc(beer.name)}</strong><small>${esc(beer.brand || "")} · ${esc(beer.country_name || "")}</small></span></label>`).join(""); return; }
  if (!event.target.matches("[data-beer-form], [data-tasting-form]")) return; event.preventDefault(); const form = event.target; const submit = form.querySelector("[type=submit]"); submit.disabled = true; try { const fd = new FormData(form); const payload = Object.fromEntries(fd.entries()); payload.flavor_tags = fd.getAll("flavor_tags"); if (form.matches("[data-beer-form]")) { const beer = form.dataset.beerId ? await beerRepository.updateBeer(form.dataset.beerId, payload) : await beerRepository.createBeer(payload); await savePendingPhotos(form, "beer", beer.id); if (form.dataset.beerId) navigate(`/beers/${beer.id}`); else firstTastingSheet(beer); } else { const tasting = form.dataset.tastingId ? await tastingRepository.updateTasting(form.dataset.tastingId, payload) : await tastingRepository.createTasting(payload); await savePendingPhotos(form, "tasting", tasting.id); navigate(`/tastings/${tasting.id}`); } } catch (error) { window.alert(error.message || "保存失败，请重试"); submit.disabled = false; } });

async function hideKeyboard() { await globalThis.Capacitor?.Plugins?.Keyboard?.hide?.().catch?.(() => {}); document.activeElement?.blur?.(); }
function isKeyboardVisible() { const active = document.activeElement; return Boolean(active?.matches?.("input,textarea,select") && ((window.visualViewport && window.innerHeight - window.visualViewport.height > 100) || active !== document.body)); }
async function goBack() { if (isKeyboardVisible()) { await hideKeyboard(); return; } if (overlayManager.hasOpenOverlay()) { overlayManager.closeTopOverlay(); return; } const current = normalizeRoute(route().split("?")[0]); if (current !== HOME && window.history.length > 1) { window.history.back(); return; } if (current !== HOME) { navigate(HOME, true); return; } if (Date.now() < exitArmedUntil) { App.exitApp?.(); return; } exitArmedUntil = Date.now() + 2200; window.alert("再次按返回键退出 Beer Journal"); setTimeout(() => { exitArmedUntil = 0; }, 2200); }
App.addListener?.("backButton", goBack);
App.addListener?.("appStateChange", ({ isActive }) => {
  // Returning from the native photo picker/camera must not recreate an active
  // form: doing so would discard unsaved fields and pending photo previews.
  if (isActive && !document.querySelector("[data-beer-form], [data-tasting-form]")) render();
});
window.addEventListener("hashchange", render); window.addEventListener("popstate", render);
window.addEventListener("pageshow", () => {
  // Native pickers can resume the WebView with a pageshow event. Keep an
  // active form intact so unsaved fields and pending photo previews survive.
  if (!document.querySelector("[data-beer-form], [data-tasting-form]")) render();
});
async function initialize() { try { await preloadLogo(); await initializeDatabase(); await render(); } catch (error) { dbError = error; await render(); } }
if (!window.location.hash) window.history.replaceState({}, "", `#${HOME}`);
initialize();
